import sailpoint.tools.GeneralException;

int MAX_TRIES = 100;

String idtyType = identity.getAttribute("identityType");

if ("partner".equals(idtyType)) {
    String acctID = identity.getStringAttribute("itauloginebusiness");
    if(acctID !=null){
        return "uid=" + acctID + ",cn=users,dc=rc,dc=itau";
    }
} else if ("service".equals(idtyType)){

    String identityName = identity.getName();
    int size = 7 - identityName.length();
    for (int i = 1; i < MAX_TRIES; i++) {
        String sequence = "" + i;
        while (sequence.length() < size) {
            sequence = "0" + sequence;
        }
        String username = "uid=" + identityName + sequence + ",cn=SvcAccounts,dc=rc,dc=itau";
        if (idn.isUniqueAccountId(identity.getName(), application.getName(), username)) {
            return username;
        }
    }
    throw new GeneralException("OCI-UsernameGenerator: Unable to generate unique username after " + MAX_TRIES + " attempts.");
} else {
    String acctID = identity.getAttribute("itaufuncional");
    if (acctID != null && !acctID.trim().isEmpty()) {
        acctDN = "uid=" + acctID.trim() + ",cn=users,dc=rc,dc=itau";
    }
    return acctDN;
}
